		sig4->instanceInitmlczerovSIG4(sample_rate);
		sig4->fillmlczerovSIG4(2001, ftbl4mlczerovSIG4);
		mlczerovSIG5* sig5 = newmlczerovSIG5();
		sig5->instanceInitmlczerovSIG5(sample_rate);
		sig5->fillmlczerovSIG5(2001, ftbl5mlczerovSIG5);
		mlczerovSIG6* sig6 = newmlczerovSIG6();
		sig6->instanceInitmlczerovSIG6(sample_rate);
		sig6->fillmlczerovSIG6(2001, ftbl6mlczerovSIG6);
		mlczerovSIG7* sig7 = newmlczerovSIG7();
		sig7->instanceInitmlczerovSIG7(sample_rate);
		sig7->fillmlczerovSIG7(2001, ftbl7mlczerovSIG7);
		mlczerovSIG8* sig8 = newmlczerovSIG8();
		sig8->instanceInitmlczerovSIG8(sample_rate);
		sig8->fillmlczerovSIG8(2001, ftbl8mlczerovSIG8);
		mlczerovSIG9* sig9 = newmlczerovSIG9();
		sig9->instanceInitmlczerovSIG9(sample_rate);
		sig9->fillmlczerovSIG9(2001, ftbl9mlczerovSIG9);
		mlczerovSIG10* sig10 = newmlczerovSIG10();
		sig10->instanceInitmlczerovSIG10(sample_rate);
