		sig11->instanceInitmlczerovSIG11(sample_rate);
		sig11->fillmlczerovSIG11(2001, ftbl11mlczerovSIG11);
		deletemlczerovSIG0(sig0);
		deletemlczerovSIG1(sig1);
		deletemlczerovSIG2(sig2);
		deletemlczerovSIG3(sig3);
		deletemlczerovSIG4(sig4);
